-- ----------------------------
-- Table structure for province_panel_data
-- ----------------------------
DROP TABLE IF EXISTS `province_panel_data`;
CREATE TABLE `province_panel_data`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '自增ID',
  `province` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '省份名称（如上海市、云南省）',
  `year` int NOT NULL COMMENT '年份（如2000、2001）',
  `carbon_intensity` double NULL DEFAULT NULL COMMENT '碳排放强度（对应historyData里的value）',
  `gfi_std` double NULL DEFAULT NULL COMMENT '绿色金融指数（gfi_std列）',
  `ln_pop` double NULL DEFAULT NULL COMMENT '人口对数（ln_pop列）',
  `energy_intensity` double NULL DEFAULT NULL COMMENT '能源强度（energy_intensity列）',
  `energy_per_capita` double NULL DEFAULT NULL COMMENT '人均能源消耗（energy_per_capita列）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_province_year`(`province` ASC, `year` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 751 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '省份绿色金融-能源平衡面板数据表' ROW_FORMAT = Dynamic;

