-- Records of province_panel_data
-- ----------------------------

-- ----------------------------
-- Table structure for sdm_coefficients
-- ----------------------------
DROP TABLE IF EXISTS `sdm_coefficients`;
CREATE TABLE `sdm_coefficients`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '自增ID',
  `parameter` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '参数名（如gfi_std、W_碳排放强度）',
  `value` double NOT NULL COMMENT '系数数值',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'SDM模型系数表' ROW_FORMAT = Dynamic;

