-- ----------------------------
DROP TABLE IF EXISTS `descriptive_statistics`;
CREATE TABLE `descriptive_statistics`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `variable_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '变量名（CSV 首列）',
  `count` double NULL DEFAULT NULL,
